var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 외곽 구역\\n<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-13","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>外郭地域\\n<color=#ffd34c>プリドウェン機関</color>秘密隔離施設LAKE-13","ENG":"[[","TWN":"管理局直轄都市<color=#ffd34c>查雷德</color>外郭區域\\n<color=#ffd34c>普利多溫機關</color>祕密隔離設施LAKE-13","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 좀 늦었군요, 버넷.","JPN":"お待たせしましたわ、バーネット。","ENG":"I seem to have run a bit late, Burnett.","TWN":"我來晚了，伯內特。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 그녀의 상태는 어떻죠?","JPN":"それで、彼女の様子は？","ENG":"So, how is her condition?","TWN":"所以，她的狀態如何？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"보고한대로. 폭주하기 직전의 파편을 봉인하는 데는 성공했어.","JPN":"報告した通りだ。なんとか暴走する直前に破片を封印できた。","ENG":"As reported. We managed to seal the Fragment just before it had an outburst.","TWN":"跟報告一樣，已經成功封印即將暴走的碎片。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"리오나는 아직 의식을 되찾지 못했지만…….","JPN":"リオナはまだ意識が戻ってないが……","ENG":"Liona still hasn't regained consciousness...","TWN":"雖然萊歐娜還沒有恢復意識……"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니요, 현 시점에서 그녀가 의식을 되찾으면 우리야 말로 곤란해요.","JPN":"いいえ、現時点で彼女が意識を取り戻したら困ります。","ENG":"No. At this point, it would be worse if she did wake up.","TWN":"不，要是她在這個時間點醒來，反而會讓我們為難。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그녀</color>가 정말로 <color=#ffd34c>그녀</color>인지 확신할 수 없으니까요.","JPN":"<color=#ffd34c>彼女</color>が本当に<color=#ffd34c>彼女</color>なのか、確信できませんから。","ENG":"Because we can't be certain that <color=#ffd34c>she</color> is truly <color=#ffd34c>her</color>.","TWN":"因為無法確定<color=#ffd34c>她</color>究竟是不是<color=#ffd34c>她</color>。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그게 무슨 소리야? ","JPN":"どういう意味？ ","ENG":"What do you mean by that?","TWN":"那是什麼意思？ "},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온이 리온이 아닐 수도 있다고? 토토가 리온의 몸을 빼앗았다는 거야?","JPN":"リオンが、リオンじゃないかもしれない……？　トトがリオンの体を乗っ取ったってこと？","ENG":"Are you saying Liona might not be Liona anymore? That Toto took over her body?","TWN":"你是說萊恩可能已經不是萊恩了？托托奪走了萊恩的身體嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아……!","JPN":"そんなわけないよ……！","ENG":"That can't be true...!","TWN":"怎麼可能……！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"생긴 게 좀 괴상하기는 해도, 토토는 리온의 둘도 없는 친구야……!","JPN":"見た目はちょっと変でも、トトはリオンのかけがえない友達なんだ……！","ENG":"Even if he looks strange, Toto is Liona's one and only friend...!","TWN":"就算長得有點怪，托托是萊恩獨一無二的朋友……！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 우리의 친구이기도 해.","JPN":"それに……私たちの友達でもある。","ENG":"And our friend too.","TWN":"而且也是我們的朋友。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그런데 친구가 친구의 몸을 뺏는다고? 내가 그 말을 믿을 것 같아……?","JPN":"なのに、友達が友達の体を奪う？　そんな話信じられるわけないだろ……","ENG":"So you're saying a friend would steal another friend's body? Do you really expect me to believe that...?","TWN":"朋友會奪走朋友的身體？你覺得我會相信這種話嗎……？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시…….","JPN":"ドロシー……","ENG":"Dorothy...","TWN":"桃樂絲……"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당신들, 프리드웬 맞지?","JPN":"あんたたち、プリドウェンだよな。","ENG":"You're Prydwen, right?","TWN":"你們是普利多溫對吧？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온이 샤레이드에 찾아온 이유는 당신들을 찾기 위해서였어.","JPN":"リオンがシャレードに来たのは、あんたたちを探すためだった。","ENG":"Liona came to Charade to find you.","TWN":"萊恩會來到查雷德，就是為了找你們。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"프리드웬에서 <color=#ffd34c>초대장</color>을 보냈다면서 말이야.","JPN":"プリドウェンから<color=#ffd34c>招待状</color>が送られてきたって言って。","ENG":"She said Prydwen sent an <color=#ffd34c>invitation</color>.","TWN":"她說普利多溫寄出了<color=#ffd34c>邀請函</color>。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"설마 당신들은 처음부터 이렇게 될 줄 알고 있었던 거야?","JPN":"まさかあんたたち、最初からこうなるって知ってたのか？","ENG":"Don't tell me you knew this would happen from the start?","TWN":"難道你們從一開始就知道會變成這樣嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"초대장이라고요?","JPN":"招待状？","ENG":"An invitation?","TWN":"邀請函？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"영문을 모르겠군요. 기관은 관리 대상에게 초대장 같은 걸 보내지 않습니다.","JPN":"訳がわかりませんね。機関が管理対象に招待状を送ることはありません。","ENG":"I'm afraid I have no idea what you mean. The Institution does not send invitations to those under special surveillance.","TWN":"我不太明白，機關並不會向管理對象寄送邀請函之類的東西。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐? 관리 대상? 지금 말 다 했어?","JPN":"は？　管理対象？　言わせておけば！","ENG":"What? Special surveillance? Are you even hearing yourself?","TWN":"什麼？管理對象？你說完了嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다 못했습니다. 애초에 그녀가 갑자기 사라져서 곤란한 건……","JPN":"まだあります。そもそも彼女が突然姿を消して迷惑しているのは……","ENG":"I'm not finished. In the first place, the real problem was that she suddenly disappeared–","TWN":"還沒呢。一開始她突然消失，讓我們也很困擾……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흐읍!","JPN":"ふっ！","ENG":"Hmph!","TWN":"唔！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"기관장, 여기선 나한테 맡겨.","JPN":"機関長、ここは任せてくれ。","ENG":"Chief, leave this to me.","TWN":"機關長，這裡交給我吧。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"내가 설명할 테니까.","JPN":"俺が説明する。","ENG":"I'll explain.","TWN":"我來說明。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……물벼룩 주제에 손버릇이 고약해졌군요.","JPN":"……ミジンコのくせに、手癖が悪くなりましたわね。","ENG":"...You're getting awfully handsy, Water Flea.","TWN":"……區區水蚤，手腳倒是越來越不老實了。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흥, 마음대로 하세요.","JPN":"ふん、好きにしなさい。","ENG":"Hmph. Do as you please.","TWN":"哼，隨便你。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"우선은 사과할게, 도로시 그리고 허수아.","JPN":"まず謝るよ。ドロシー、あとカカシ・コトリ。","ENG":"First, let me apologize, Dorothy. And you too, Skia Crow.","TWN":"首先我要跟你們道歉，桃樂絲，還有禾蘇亞。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"우리 프리드웬 기관은 아주 오래전부터 너희와 네 친구를 감시하고 있었어.","JPN":"俺たちプリドウェン機関はかなり前からお前たちを監視していた。","ENG":"The Prydwen Institution has been monitoring you and your friends for a very long time.","TWN":"我們普利多溫機關從很久以前就一直在監視你們，還有你們的朋友。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그리고 너희가 신성 파편의 폭주로 인해, 끔찍한 사고를 당했다는 것도 이미 알고 있고.","JPN":"数年前にあった、神聖の破片が暴走した事件のせいでお前たちが酷い目に遭ったことも知っている。","ENG":"And we already knew that you were caught in a horrific accident caused by a rampaging Divinity Fragment.","TWN":"而且我們也早就知道你們因為神聖碎片暴走，遭遇那場可怕意外的事了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"신성 파편이라고……?","JPN":"神聖の破片……？","ENG":"Divinity Fragment...?","TWN":"神聖碎片……？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"저길 봐.","JPN":"あれを見ろ。","ENG":"Look over there.","TWN":"你看那個。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};